     * >>> findLargestSubstring(Arrays.asList("rose", "orchid"))
     * 2
     */
    public int findLargestSubstring(List<String> strings)  {
        if (strings == null || strings.isEmpty()) return 0;
        if (strings.size() == 1) return strings.get(0).length();

        Collections.sort(strings);
        int size = strings.get(0).length();
        int count = 0;
        String x = strings.get(0);
        String y = new StringBuilder(x).reverse().toString();

        for (int i = 1; i < strings.size(); i++) {
            count = Math.max(count, strings.get(i).length());
            if (!strings.get(i).contains(x) &&!strings.get(i).contains(y)) {
                count = Math.max(count, i);
                x = strings.get(i);
                y = new StringBuilder(x).reverse().toString();
                size = x.length();
            }
        }
        return Math.min(size, count);
    }
}

